/**
 * Theme bucket used by the diagnostics panel to group matched phrases.
 */
export type HandwavyCategory =
  (typeof HandwavyCategory)[keyof typeof HandwavyCategory];

export const HandwavyCategory = {
  absence: "absence",
  hedging: "hedging",
  buzzword: "buzzword",
} as const;

export type HandwavyEditEntryCategory = {
  from: HandwavyCategory;
  to: HandwavyCategory;
};

/**
 * Before/after values for the rationale text. Empty string indicates the rationale was set or cleared.
 */
export type HandwavyEditEntryRationale = {
  from?: string;
  to?: string;
};

/**
 * Task #247 — before/after values for the phrase string itself,
present only when the reviewer renamed the marker via the
edit endpoint's `newPhrase` field. Both values are stored
already normalized (lowercase + collapsed whitespace).

 */
export type HandwavyEditEntryPhrase = {
  from: string;
  to: string;
};

/**
 * Single in-place edit applied to a curated hand-wavy marker phrase.
Records who made the change, when, and the before/after for whichever
fields actually changed (`category`, `rationale`, and/or — Task
#247 — the phrase string itself when a reviewer renamed it).
Fields that did not change are omitted to keep the audit log
compact.

 */
export interface HandwavyEditEntry {
  /** Reviewer name or email that performed the edit. Absent when no reviewer was supplied. */
  editedBy?: string;
  /** ISO 8601 timestamp of the edit. */
  editedAt: string;
  category?: HandwavyEditEntryCategory;
  /** Before/after values for the rationale text. Empty string indicates the rationale was set or cleared. */
  rationale?: HandwavyEditEntryRationale;
  /** Task #247 — before/after values for the phrase string itself,
present only when the reviewer renamed the marker via the
edit endpoint's `newPhrase` field. Both values are stored
already normalized (lowercase + collapsed whitespace).
 */
  phrase?: HandwavyEditEntryPhrase;
}

export interface HandwavyMarker {
  phrase: string;
  category: HandwavyCategory;
  /** Reviewer name or email that added the phrase. Absent for curated defaults. */
  addedBy?: string;
  /** ISO 8601 timestamp the phrase was added. Absent for curated defaults. */
  addedAt?: string;
  /** Free-text justification supplied by the reviewer at add time. */
  rationale?: string;
  /** Chronological log of in-place edits to this marker (most recent
last). Each entry records who changed what, when. Bounded
server-side per marker.
 */
  edits?: HandwavyEditEntry[];
}

/**
 * Task #135 — one element of a batch-removal history entry's `phrases`
array. Mirrors the audit metadata that a single-removal entry carries
at its top level. Per-phrase `reinstated*` fields track partial
reinstates so a reviewer can pull individual phrases back out of a
batch removal.

 */
export interface HandwavyBatchHistoryPhrase {
  phrase: string;
  category: HandwavyCategory;
  addedBy?: string;
  addedAt?: string;
  rationale?: string;
  /** Preserved on remove so reinstating still shows the edit history. */
  edits?: HandwavyEditEntry[];
  reinstated?: boolean;
  reinstatedBy?: string;
  reinstatedAt?: string;
}

/**
 * Removed-phrase audit record used so reviewers can reinstate a phrase
with original context. Single-removal entries populate `phrase` +
`category`; Task #135 batch-removal entries leave those empty and
instead populate `phrases` with the list of removed phrases.

 */
export interface HandwavyHistoryEntry {
  /** The removed phrase (single-removal entries). Empty/omitted on
Task #135 batch entries — see `phrases` instead.
 */
  phrase?: string;
  category?: HandwavyCategory;
  addedBy?: string;
  addedAt?: string;
  rationale?: string;
  /** Task */
  edits?: HandwavyEditEntry[];
  /** Reviewer name or email that removed the phrase(s). */
  removedBy?: string;
  /** ISO 8601 timestamp the phrase(s) were removed. */
  removedAt: string;
  /** Task #121 — true once a reviewer has reinstated this phrase
straight from the history log via POST
/feedback/calibration/handwavy-phrases/reinstate. The same row
cannot be reinstated twice — if the phrase is removed again, a
new history row is appended. For Task #135 batch entries this
is the AGGREGATE flag: true once every inner phrase has been
reinstated (see `phrases[].reinstated`).
 */
  reinstated?: boolean;
  /** Reviewer name or email that reinstated the phrase from this history entry. */
  reinstatedBy?: string;
  /** ISO 8601 timestamp the phrase was reinstated from this history entry. */
  reinstatedAt?: string;
  /** Task #130 — true when this history row was produced by a reviewer
undoing a brand-new add via POST
/feedback/calibration/handwavy-phrases/undo. The UI renders these
rows distinctly from manual removals so the audit trail clearly
reads "added then undone" rather than "added then removed".
 */
  undone?: boolean;
  /** Reviewer name or email that pressed Undo on this entry. */
  undoneBy?: string;
  /** Task #135 — present when the entry represents a batch removal.
Each item lists one removed phrase plus its original add-history
metadata and per-phrase reinstate state.
 */
  phrases?: HandwavyBatchHistoryPhrase[];
}

/**
 * Task #160 — Slim summary of one BATCH removal entry from the hand-wavy
phrase history log, scoped to the fields the reinstate-batch CLI
picker needs to show (timestamp, reviewer, phrase count,
already-reinstated flag, plus a small sample of removed phrases).

 */
export interface HandwavyPhraseRemovalBatchSummary {
  /** ISO 8601 timestamp of the batch removal entry. Pass back to /reinstate-batch as `removedAt`. */
  removedAt: string;
  /** Reviewer name or email recorded on the batch removal. Omitted if the original removal didn't supply one. */
  removedBy?: string;
  /** Number of phrases that were removed in this batch. */
  phraseCount: number;
  /** Aggregate flag — true once every inner phrase from this batch has already been reinstated. */
  reinstated: boolean;
  /**
   * First few removed phrases (capped at 5), shown in the picker so reviewers can identify the batch at a glance.
   * @maxItems 5
   */
  samplePhrases: string[];
}

/**
 * Task #160 — Response from GET
/feedback/calibration/handwavy-phrases/removal-batches. Newest batches
are returned first.

 */
export interface HandwavyPhraseRemovalBatchesList {
  /** Effective page size used for this response. */
  limit: number;
  /** Total number of batch removal entries in the history log (regardless of `limit`). */
  totalBatches: number;
  batches: HandwavyPhraseRemovalBatchSummary[];
}

/**
 * Task #176 — Detail response for one batch removal entry. Echoes the
FULL inner phrase list with per-phrase audit metadata so the
reinstate-batch CLI (and the Task #244 web reviewer picker) can
render every phrase the action would touch — not just the
5-phrase sample the list endpoint returns. `reinstatedCount`
/ `reinstated` together let callers spot a partial- or
already-fully-reinstated batch before re-firing the action.

 */
export interface HandwavyPhraseRemovalBatchDetail {
  /** ISO 8601 timestamp of the parent batch removal entry (echoes the path parameter). */
  removedAt: string;
  /** Reviewer name or email recorded on the batch removal. Omitted if the original removal didn't supply one. */
  removedBy?: string;
  /** Aggregate flag — true once every inner phrase from this batch has been reinstated. */
  reinstated: boolean;
  /** ISO 8601 timestamp the batch was fully reinstated, when `reinstated` is true. */
  reinstatedAt?: string;
  /** Reviewer name or email recorded on the batch-level reinstate, when `reinstated` is true. */
  reinstatedBy?: string;
  /** Total number of phrases in this batch. */
  phraseCount: number;
  /** Number of inner phrases that have already been reinstated (per-phrase or via a prior batch reinstate). */
  reinstatedCount: number;
  /** Full inner phrase list with per-phrase audit metadata. */
  phrases: HandwavyBatchHistoryPhrase[];
}

export type HandwavyPhraseRemovalBatchDetailErrorReason =
  (typeof HandwavyPhraseRemovalBatchDetailErrorReason)[keyof typeof HandwavyPhraseRemovalBatchDetailErrorReason];

export const HandwavyPhraseRemovalBatchDetailErrorReason = {
  "history-not-found": "history-not-found",
  "not-a-batch": "not-a-batch",
} as const;

/**
 * Task #176 — 404 response shape for the batch detail endpoint.
`reason` discriminates between "no matching removal-history entry"
and "matched a single-phrase removal" so callers can format a
targeted hint (e.g. the CLI suggests /reinstate for the latter).

 */
export interface HandwavyPhraseRemovalBatchDetailError {
  error: string;
  reason: HandwavyPhraseRemovalBatchDetailErrorReason;
}

export interface HandwavyPhrasesList {
  phrases: HandwavyMarker[];
  total: number;
  /** Removal audit log (most recent last). Bounded server-side. */
  history: HandwavyHistoryEntry[];
}

/**
 * Request body for the in-place edit endpoint. The `phrase` string
identifies which curated marker to update; provide at least one of
`category`, `rationale`, or `newPhrase` to actually change
something. Send an empty `rationale` string to clear an existing
rationale. Task #247 — `newPhrase` is the rename target; the edit
only changes the row identity when its normalized form differs
from the existing phrase, otherwise it is treated as a no-op.

 */
export interface HandwavyPhraseEditBody {
  /** Existing curated phrase to edit (matched after lowercase + whitespace normalization). */
  phrase: string;
  category?: HandwavyCategory;
  /** New rationale text. Empty string clears the existing rationale. */
  rationale?: string;
  /** Task #247 — Rename target. Normalized to lowercase + collapsed
whitespace before matching, and rejected when the normalized
form already belongs to another active marker. When the
normalized form matches the existing `phrase`, the rename is a
no-op; the request can still apply concurrent
`category`/`rationale` updates.
 */
  newPhrase?: string;
  /** Reviewer name or email recorded in the edit audit entry. Optional. */
  reviewer?: string;
}

export interface HandwavyPhraseBody {
  /** Marker phrase (case-insensitive substring match against report text after whitespace collapsing). */
  phrase: string;
  category?: HandwavyCategory;
  /** Task #114 — when true on POST, the server does NOT persist the phrase. It runs the
candidate phrase against the curated benchmark corpus (T1 LEGIT / T2 BORDERLINE
/ T3 SLOP / T4 HALLUCINATED fixtures) and returns a `dryRunMatches` block so
reviewers can see how many GREEN / YELLOW reports the phrase would have hit
before they confirm the add.

Task #155 — when true on DELETE for a single phrase, the server does NOT
mutate the active list, history, or cache and instead returns a
`HandwavyPhraseSingleRemoveDryRunResponse` (the same corpus + production
removal-impact summary as the batch dry-run, with `batch: false`).

Defaults to false (write-through behavior).
 */
  dryRun?: boolean;
  /** Reviewer name or email recorded in the audit trail. Optional. */
  reviewer?: string;
  /** Free-text justification recorded with the phrase. Only consulted on POST. */
  rationale?: string;
  /**
   * Task #125 — optional override for the upper bound on the production-archive
scan that backs the dry-run preview. Only consulted on the dry-run path
(the only place the production scan runs). Heavy-user installs can widen
the window for a stronger false-positive signal; small installs can tighten
it to focus on recent reporter behavior. Defaults to 2000 when omitted so
existing reviewers see no behavior change. The chosen value is echoed back
in `dryRunMatchesProductionLimit` so the UI can label the second signal
accurately.

Task #230 — also accepted on the DELETE single-phrase dry-run path
via `HandwavyPhraseBody`, which shares this body schema, so the
same reviewer-chosen window drives the single-phrase removal preview
too. The chosen value is echoed back in
`HandwavyPhraseSingleRemoveDryRunResponse.dryRunImpact.productionLimit`.

   * @minimum 100
   * @maximum 10000
   */
  productionScanLimit?: number;
}

/**
 * Task #130 — body for POST /feedback/calibration/handwavy-phrases/undo.
The active marker is matched by `phrase` + `addedAt`; the request is
rejected with 409 if the marker is older than the server-side undo
window (default 5 minutes).

 */
export interface HandwavyPhraseUndoBody {
  /** The (already-normalized) phrase of the live marker to undo. */
  phrase: string;
  /** ISO 8601 timestamp from the live marker's `addedAt` field. */
  addedAt: string;
  /** Reviewer name or email recorded as `removedBy`/`undoneBy` on the resulting history row. Optional. */
  reviewer?: string;
}

/**
 * Task #233 — one `(phrase, addedAt)` pair to undo as part of a batch.
Mirrors the single-undo body fields; see `HandwavyPhraseUndoBody`
for the matching contract.

 */
export interface HandwavyPhraseUndoBatchEntry {
  /** The (already-normalized) phrase of the live marker to undo. */
  phrase: string;
  /** ISO 8601 timestamp from the live marker's `addedAt` field. */
  addedAt: string;
}

/**
 * Task #233 — body for POST /feedback/calibration/handwavy-phrases/undo-batch.
The reviewer's UI walks every reviewer-added marker that's still
inside its per-marker undo window and sends each one as a pair
in `entries`. The server runs each entry through the per-marker
undo path so every successful undo still produces its own
`undone: true` history row (no batch-merge row that hides
per-phrase provenance). Capped at 200 entries per call.

 */
export interface HandwavyPhraseUndoBatchBody {
  /**
   * @minItems 1
   * @maxItems 200
   */
  entries: HandwavyPhraseUndoBatchEntry[];
  /** Reviewer name or email recorded as `removedBy`/`undoneBy` on every successful undo's history row. Optional. */
  reviewer?: string;
}

/**
 * Present only when `undone` is false.
 */
export type HandwavyPhraseUndoBatchEntryResultReason =
  (typeof HandwavyPhraseUndoBatchEntryResultReason)[keyof typeof HandwavyPhraseUndoBatchEntryResultReason];

export const HandwavyPhraseUndoBatchEntryResultReason = {
  "not-found": "not-found",
  "addedAt-mismatch": "addedAt-mismatch",
  "no-addedAt": "no-addedAt",
  "window-expired": "window-expired",
} as const;

/**
 * Task #233 — outcome of attempting to undo one `(phrase, addedAt)`
pair as part of a /undo-batch round-trip. Mirrors the
single-undo failure reasons so the UI can render the same per-row
explanations the per-row Undo button already surfaces.

 */
export interface HandwavyPhraseUndoBatchEntryResult {
  phrase: string;
  undone: boolean;
  /** Present only when `undone` is false. */
  reason?: HandwavyPhraseUndoBatchEntryResultReason;
  /** Present only when `undone` is true. The fresh `undone:true` history row appended for this phrase. */
  historyEntry?: HandwavyHistoryEntry;
}

/**
 * Task #233 — response from POST /feedback/calibration/handwavy-phrases/undo-batch.
`phrases` and `history` echo the post-batch active list and audit
log so callers can refresh their cached views in one round-trip.

 */
export interface HandwavyPhraseUndoBatchResponse {
  /** Always true on a successful response (the batch was processed). */
  undone: boolean;
  /** Always true — distinguishes this response from a single-phrase /undo. */
  batch: boolean;
  /** Number of entries actually undone in this round-trip. */
  undoneCount: number;
  /** Number of entries skipped (any non-success per-entry reason). */
  skipped: number;
  /** Number of active phrases after the batch. */
  total: number;
  results: HandwavyPhraseUndoBatchEntryResult[];
  phrases: HandwavyMarker[];
  history: HandwavyHistoryEntry[];
}

/**
 * Task #132 — body for POST /feedback/calibration/handwavy-phrases/revert-edit.
The edit entry is matched by `phrase` + `editedAt`.

 */
export interface HandwavyPhraseRevertEditBody {
  /** Existing curated phrase (matched after lowercase + whitespace normalization). */
  phrase: string;
  /** ISO 8601 timestamp of the `edits` entry to undo. */
  editedAt: string;
  /** Reviewer name or email recorded on the inverse edit entry. Optional. */
  reviewer?: string;
}

/**
 * Task #135 — batch removal request body for DELETE
/feedback/calibration/handwavy-phrases. Sends up to 200 phrases in
one round-trip; the server runs a single in-memory pass, a single
file rewrite, and appends ONE history entry that lists every removed
phrase. Mutually exclusive with the single-phrase `phrase` field.

Task #145 — when `dryRun: true` the server returns a preview
(`HandwavyPhraseBatchRemoveDryRunResponse`) that mirrors the
post-mutation per-phrase results plus a corpus impact summary, but
does NOT mutate the active list, the history log, or the cache.

 */
export interface HandwavyPhraseBatchRemoveBody {
  /**
   * List of phrases to remove. Normalized server-side.
   * @minItems 1
   * @maxItems 200
   */
  phrases: string[];
  /** Reviewer name or email recorded on the batch history entry. Optional. */
  reviewer?: string;
  /** When true, return a removal preview (corpus impact + per-phrase outcomes) without mutating the active list. */
  dryRun?: boolean;
  /**
   * Task #229 / #230 — optional override for the upper bound on the
production-archive scan that backs the bulk-removal dry-run. Mirrors the
same field on `HandwavyPhraseBody` (Task #125) so the reviewer-chosen scan
window persisted in the calibration UI applies to every production-archive
scan, not just the add-phrase preview. Only consulted on the dry-run path,
but validated on every DELETE so a malformed value never silently slips into
a real bulk delete. Heavy-user installs can widen the window for a sharper
"valid detections lost" signal; small installs can tighten it. Defaults to
2000 when omitted so existing reviewers see no behavior change. The chosen
value is echoed back in
`HandwavyPhraseBatchRemoveDryRunResponse.dryRunImpact.productionLimit`.

   * @minimum 100
   * @maximum 10000
   */
  productionScanLimit?: number;
}

export type HandwavyPhraseBatchRemoveDryRunImpactByTier = {
  t1Legit: number;
  t2Borderline: number;
  t3Slop: number;
  t4Hallucinated: number;
};

export type HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemTier =
  (typeof HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemTier)[keyof typeof HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemTier];

export const HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemTier = {
  T1_LEGIT: "T1_LEGIT",
  T2_BORDERLINE: "T2_BORDERLINE",
  T3_SLOP: "T3_SLOP",
  T4_HALLUCINATED: "T4_HALLUCINATED",
} as const;

/**
 * Task #345 — A short context snippet (~80 chars centered on the
matched phrase) cut from the row's original text so a reviewer
can judge the un-flag in place without opening /verify/:id.
Returned as a structured `{ before, match, after }` triple so
the UI can render the matched phrase highlighted while the
rest of the snippet stays plain text. All three fields are
raw text — the client is responsible for escaping them when
rendering (React's text-node rendering already does this).
Null when the matched phrase could not be located in the
original text (defensive fallback; should not happen for the
flow that produced the match).

 */
export type HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemSnippet = {
  before: string;
  match: string;
  after: string;
} | null;

export type HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItem = {
  id: string;
  tier: HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemTier;
  /** Task #345 — A short context snippet (~80 chars centered on the
matched phrase) cut from the row's original text so a reviewer
can judge the un-flag in place without opening /verify/:id.
Returned as a structured `{ before, match, after }` triple so
the UI can render the matched phrase highlighted while the
rest of the snippet stays plain text. All three fields are
raw text — the client is responsible for escaping them when
rendering (React's text-node rendering already does this).
Null when the matched phrase could not be located in the
original text (defensive fallback; should not happen for the
flow that produced the match).
 */
  snippet?: HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItemSnippet;
};

/**
 * Task #145 — projected impact of a bulk removal against a single
corpus (curated benchmark fixtures or recent production reports).
`total` counts fixtures that are flagged today but would NOT be
flagged after the removal, broken down by tier. `validDetectionsLost`
is `byTier.t3Slop + byTier.t4Hallucinated` (the worrying number).
`falsePositivesDropped` is `byTier.t1Legit + byTier.t2Borderline`
(informational good news). `warning` is set when valid detections
would be lost; null otherwise.

 */
export interface HandwavyPhraseBatchRemoveDryRunImpact {
  total: number;
  byTier: HandwavyPhraseBatchRemoveDryRunImpactByTier;
  validDetectionsLost: number;
  falsePositivesDropped: number;
  corpusSize: number;
  sampleMatches: HandwavyPhraseBatchRemoveDryRunImpactSampleMatchesItem[];
  warning: string | null;
  /** Task #218 — For production scans, the earliest `createdAt` among the rows
actually included in the scanned sample (i.e. survived the label/content
filter, so the same population reflected in `corpusSize`). Reported so
reviewers using the bulk-retire flow can tell whether the impact signal
reflects current reporter behavior or a long-stale archive (e.g. "scanned
2000 reports from 2026-02-01 to 2026-04-22"). Null on the curated
benchmark block (fixtures have no wall-clock timestamp) and when the
scan was empty. Mirrors the add-time `HandwavyPhraseDryRunMatches`
field of the same name (Task #124).
 */
  oldestCreatedAt: string | null;
  /** Task #218 — For production scans, the most recent `createdAt` among the
rows actually included in the scanned sample. See `oldestCreatedAt` for
details. Null on the curated benchmark block and when the scan was empty.
 */
  newestCreatedAt: string | null;
  /** Task #323 — For production scans, the total number of label-bearing
archived reports (i.e. the addressable population the chosen scan
window is applied to, NOT just the `corpusSize` returned by the
tier-filter). Reported alongside the response's `productionLimit`
so the bulk-removal preview can warn when a reviewer-tightened
scan window covers only a small slice of the archive (e.g.
"scanning 100 of ~8,400 archived reports — recent reporter
behavior only"). Null on the curated benchmark block (the corpus
is the full fixture set, not a sample) and when the production
scan was skipped because nothing would be removed.
 */
  archiveTotal: number | null;
}

export type HandwavyPhraseBatchRemoveDryRunResponseDryRunImpact = {
  corpus: HandwavyPhraseBatchRemoveDryRunImpact;
  production?: HandwavyPhraseBatchRemoveDryRunImpact | null;
  productionError: string | null;
  productionLimit: number;
};

export type HandwavyPhraseBatchRemoveResultEntryReason =
  (typeof HandwavyPhraseBatchRemoveResultEntryReason)[keyof typeof HandwavyPhraseBatchRemoveResultEntryReason];

export const HandwavyPhraseBatchRemoveResultEntryReason = {
  "not-found": "not-found",
  "duplicate-in-batch": "duplicate-in-batch",
} as const;

/**
 * Per-phrase outcome from a Task #135 batch removal. `phrase` is the
normalized form actually compared against the active list. `reason`
is omitted on successful removals.

 */
export interface HandwavyPhraseBatchRemoveResultEntry {
  /** Original (raw) phrase as supplied by the client. */
  raw: string;
  /** Normalized form actually compared against the active list. */
  phrase: string;
  removed: boolean;
  reason?: HandwavyPhraseBatchRemoveResultEntryReason;
}

/**
 * Task #145 — preview response returned when DELETE
/feedback/calibration/handwavy-phrases is called with `dryRun: true`
on the batch path. Mirrors the post-mutation per-phrase result
shape but does NOT mutate the active list, history, or cache.

 */
export interface HandwavyPhraseBatchRemoveDryRunResponse {
  dryRun: boolean;
  batch: boolean;
  /** Count of phrases that WOULD be removed if the batch were applied. */
  wouldRemove: number;
  notFound: number;
  duplicateInBatch: number;
  /** Active list size BEFORE the batch (no mutation occurred). */
  total: number;
  /** Projected active list size AFTER the batch would be applied. */
  projectedTotal: number;
  results: HandwavyPhraseBatchRemoveResultEntry[];
  dryRunImpact: HandwavyPhraseBatchRemoveDryRunResponseDryRunImpact;
  /** Active list (unchanged because this is a dry run). */
  phrases: HandwavyMarker[];
}

export type HandwavyPhraseSingleRemoveDryRunResponseDryRunImpact = {
  corpus: HandwavyPhraseBatchRemoveDryRunImpact;
  production?: HandwavyPhraseBatchRemoveDryRunImpact | null;
  productionError: string | null;
  productionLimit: number;
};

/**
 * Task #155 — preview response returned when DELETE
/feedback/calibration/handwavy-phrases is called with `dryRun: true`
on the SINGLE-phrase path. Mirrors the batch dry-run shape (with
`batch: false`) so the in-UI Trash flow can show the same corpus +
production removal-impact warning before a one-click removal,
without mutating the active list, history, or cache.

 */
export interface HandwavyPhraseSingleRemoveDryRunResponse {
  dryRun: boolean;
  batch: boolean;
  /** 0 if the phrase is not on the active list, 1 otherwise. */
  wouldRemove: number;
  notFound: number;
  duplicateInBatch: number;
  /** Normalized form actually compared against the active list. */
  phrase: string;
  /** Original (raw) phrase as supplied by the client. */
  raw: string;
  /** Whether the phrase WOULD be removed if the call were not a dry run. */
  removed: boolean;
  reason?: "not-found" | "duplicate-in-batch" | null;
  /** Active list size BEFORE the removal (no mutation occurred). */
  total: number;
  /** Projected active list size AFTER the removal would be applied. */
  projectedTotal: number;
  /** Single-element array mirroring the batch dry-run results shape. */
  results: HandwavyPhraseBatchRemoveResultEntry[];
  dryRunImpact: HandwavyPhraseSingleRemoveDryRunResponseDryRunImpact;
  /** Active list (unchanged because this is a dry run). */
  phrases: HandwavyMarker[];
}

/**
 * Task #135 — response from a batch DELETE call. The shape is
intentionally distinct from `HandwavyPhraseMutationResponse` so
clients can disambiguate by checking `batch === true`.

 */
export interface HandwavyPhraseBatchRemoveResponse {
  batch: boolean;
  /** Count of phrases that actually came off the active list. */
  removed: number;
  /** Count of phrases that were not in the active list at lookup time. */
  notFound: number;
  /** Number of active phrases AFTER the batch. */
  total: number;
  results: HandwavyPhraseBatchRemoveResultEntry[];
  /** The single batch history entry, or null if nothing was removed. */
  historyEntry?: HandwavyHistoryEntry | null;
  /** Full active list after the batch. */
  phrases: HandwavyMarker[];
  /** Full removal audit log after the batch. */
  history: HandwavyHistoryEntry[];
}

/**
 * Task #121 — body for POST /feedback/calibration/handwavy-phrases/reinstate.
The history row is matched by `phrase` + `removedAt`.

 */
export interface HandwavyPhraseReinstateBody {
  /** The (already-normalized) phrase from the matching history entry. */
  phrase: string;
  /** ISO 8601 timestamp of the matching history entry's `removedAt` field. */
  removedAt: string;
  /** Reviewer name or email recorded as `addedBy`/`reinstatedBy` in the audit trail. Optional. */
  reviewer?: string;
}

/**
 * Task #144 — body for POST /feedback/calibration/handwavy-phrases/reinstate-batch.
The batch history entry is matched by `removedAt`; every inner phrase
that has not already been reinstated and is not currently active is
re-added in one round-trip.

Task #159 — when `dryRun: true` the server returns
`HandwavyPhraseReinstateBatchDryRunResponse` with the same per-phrase
outcome shape, and does NOT mutate the active marker list, the
removal-history log, or the cache. Both the mutating and dry-run
paths return HTTP 200; callers discriminate on the `dryRun` flag
in the response body.

 */
export interface HandwavyPhraseReinstateBatchBody {
  /** ISO 8601 timestamp of the matching batch removal entry's `removedAt` field. */
  removedAt: string;
  /** Reviewer name or email recorded as `addedBy`/`reinstatedBy` on every reinstated phrase. Optional. */
  reviewer?: string;
  /** When true, return a per-phrase reinstate preview without mutating the active list or removal-history log. */
  dryRun?: boolean;
}

/**
 * Present only when `reinstated` is false.
 */
export type HandwavyPhraseReinstateBatchEntryResultReason =
  (typeof HandwavyPhraseReinstateBatchEntryResultReason)[keyof typeof HandwavyPhraseReinstateBatchEntryResultReason];

export const HandwavyPhraseReinstateBatchEntryResultReason = {
  "already-reinstated": "already-reinstated",
  "already-active": "already-active",
} as const;

/**
 * Task #144 — outcome of attempting to reinstate one inner phrase as
part of a /reinstate-batch round-trip.

 */
export interface HandwavyPhraseReinstateBatchEntryResult {
  phrase: string;
  reinstated: boolean;
  /** Present only when `reinstated` is false. */
  reason?: HandwavyPhraseReinstateBatchEntryResultReason;
}

/**
 * Task #144 — response from POST /feedback/calibration/handwavy-phrases/reinstate-batch.

 */
export interface HandwavyPhraseReinstateBatchResponse {
  /** Always true on a successful mutating response (the batch was processed). */
  reinstated: boolean;
  /** Always true — distinguishes this response from a single-phrase /reinstate. */
  batch: boolean;
  removedAt: string;
  /** Number of inner phrases actually re-added in this round-trip. */
  reinstatedCount: number;
  /** Number of inner phrases skipped (already reinstated or already active). */
  skipped: number;
  /** Number of active phrases after the batch reinstate. */
  total: number;
  results: HandwavyPhraseReinstateBatchEntryResult[];
  historyEntry: HandwavyHistoryEntry;
  phrases: HandwavyMarker[];
  history: HandwavyHistoryEntry[];
}

/**
 * Task #159 — dry-run preview returned when POST
/feedback/calibration/handwavy-phrases/reinstate-batch is called with
`dryRun: true`. Mirrors the per-phrase outcome shape of
`HandwavyPhraseReinstateBatchResponse` so callers can reuse the same
renderer, but does NOT mutate the active marker list, the
removal-history log, or the cache. Both the mutating and dry-run
paths return HTTP 200; callers discriminate on the `dryRun` flag
in the response body.

 */
export interface HandwavyPhraseReinstateBatchDryRunResponse {
  dryRun: boolean;
  batch: boolean;
  removedAt: string;
  /** Number of inner phrases that WOULD be re-added if the batch were applied. */
  reinstatedCount: number;
  /** Number of inner phrases that would be skipped (already reinstated or already active). */
  skipped: number;
  /** Projected number of active phrases after the batch reinstate would be applied. */
  total: number;
  results: HandwavyPhraseReinstateBatchEntryResult[];
  historyEntry: HandwavyHistoryEntry;
  /** Active list (unchanged because this is a dry run). */
  phrases: HandwavyMarker[];
  /** Removal-history log (unchanged because this is a dry run). */
  history: HandwavyHistoryEntry[];
}

export type HandwavyPhraseDryRunMatchesByTier = {
  /** Matches in T1 LEGIT fixtures (GREEN — legitimate, well-evidenced). */
  t1Legit: number;
  /** Matches in T2 BORDERLINE fixtures (YELLOW — debatable signal). */
  t2Borderline: number;
  /** Matches in T3 SLOP fixtures (RED — known slop archetypes). */
  t3Slop: number;
  /** Matches in T4 HALLUCINATED fixtures (RED — fabricated/hallucinated). */
  t4Hallucinated: number;
};

export type HandwavyPhraseDryRunMatchesSampleMatchesItemTier =
  (typeof HandwavyPhraseDryRunMatchesSampleMatchesItemTier)[keyof typeof HandwavyPhraseDryRunMatchesSampleMatchesItemTier];

export const HandwavyPhraseDryRunMatchesSampleMatchesItemTier = {
  T1_LEGIT: "T1_LEGIT",
  T2_BORDERLINE: "T2_BORDERLINE",
  T3_SLOP: "T3_SLOP",
  T4_HALLUCINATED: "T4_HALLUCINATED",
} as const;

export type HandwavyPhraseDryRunMatchesSampleMatchesItem = {
  id: string;
  tier: HandwavyPhraseDryRunMatchesSampleMatchesItemTier;
};

/**
 * Task #114 — preview of how a candidate FLAT hand-wavy phrase would have flagged
the curated benchmark corpus. `falsePositives` is the count of T1 LEGIT (GREEN)
and T2 BORDERLINE (YELLOW) fixtures the substring would have matched — a high
value is a strong signal that the phrase will crater AVRI for legitimate reports.

 */
export interface HandwavyPhraseDryRunMatches {
  /** Total number of corpus fixtures the candidate phrase matched. */
  total: number;
  byTier: HandwavyPhraseDryRunMatchesByTier;
  /** T1 + T2 hits — the count of GREEN/YELLOW corpus reports that would have been flagged. */
  falsePositives: number;
  /** Total number of corpus fixtures evaluated. */
  corpusSize: number;
  /**
   * Up to 12 sample matched fixtures (id + tier) for reviewer review.
   * @maxItems 12
   */
  sampleMatches: HandwavyPhraseDryRunMatchesSampleMatchesItem[];
  /** Reviewer-facing warning string when the phrase would flag legitimate reports
(`falsePositives > 0`). Null when there are no GREEN/YELLOW hits.
 */
  warning?: string | null;
  /** Task #124 — For production scans, the earliest `createdAt` among the rows
actually included in the scanned sample (i.e. survived the label/content
filter, so the same population reflected in `corpusSize`). Reported so
reviewers can tell whether the false-positive signal reflects current
reporter behavior or a long-stale archive (e.g. "scanned 2000 reports
from 2026-02-01 to 2026-04-22"). Null on the curated benchmark block
(fixtures have no wall-clock timestamp) and when the scan was empty.
 */
  oldestCreatedAt: string | null;
  /** Task #124 — For production scans, the most recent `createdAt` among the
rows actually included in the scanned sample. See `oldestCreatedAt` for
details. Null on the curated benchmark block and when the scan was empty.
 */
  newestCreatedAt: string | null;
}

/**
 * How the candidate relates to the existing curated phrase:
- `equal`: identical normalized text (exact duplicate).
- `candidate-contains-existing`: candidate is broader; it would
  supersede the existing entry (anything matching the existing
  phrase would also match the candidate).
- `existing-contains-candidate`: candidate is narrower; the
  existing phrase already covers everything the candidate would.

 */
export type HandwavyPhraseDryRunOverlapsMatchesItemRelation =
  (typeof HandwavyPhraseDryRunOverlapsMatchesItemRelation)[keyof typeof HandwavyPhraseDryRunOverlapsMatchesItemRelation];

export const HandwavyPhraseDryRunOverlapsMatchesItemRelation = {
  equal: "equal",
  "candidate-contains-existing": "candidate-contains-existing",
  "existing-contains-candidate": "existing-contains-candidate",
} as const;

export type HandwavyPhraseDryRunOverlapsMatchesItem = {
  /** The existing curated phrase that the candidate overlaps with. */
  phrase: string;
  category: HandwavyCategory;
  /** How the candidate relates to the existing curated phrase:
- `equal`: identical normalized text (exact duplicate).
- `candidate-contains-existing`: candidate is broader; it would
  supersede the existing entry (anything matching the existing
  phrase would also match the candidate).
- `existing-contains-candidate`: candidate is narrower; the
  existing phrase already covers everything the candidate would.
 */
  relation: HandwavyPhraseDryRunOverlapsMatchesItemRelation;
};

/**
 * Task #123 — overlap signal between a candidate FLAT hand-wavy phrase and the
already-curated active list. A non-empty `matches` array means adding the
candidate would be redundant (or partially redundant) with an existing entry,
which the reviewer should see BEFORE confirming the add. The relation tells
the reviewer whether the candidate is an exact duplicate, a broader phrase
that would supersede an existing one, or a narrower phrase already covered
by an existing entry.

 */
export interface HandwavyPhraseDryRunOverlaps {
  /** Number of curated entries the candidate overlaps with. */
  total: number;
  matches: HandwavyPhraseDryRunOverlapsMatchesItem[];
}

export interface HandwavyPhraseMutationResponse {
  /** True when POST appended the phrase. Omitted on PATCH/DELETE responses. */
  added?: boolean;
  /** True when PATCH actually changed the marker; false when the supplied updates matched the existing values. Omitted on POST/DELETE responses. */
  edited?: boolean;
  editEntry?: HandwavyEditEntry;
  /** True when DELETE removed the phrase. Omitted on POST responses. */
  removed?: boolean;
  /** Task #121 — true when the response is from POST
/feedback/calibration/handwavy-phrases/reinstate. Omitted on plain
POST/DELETE responses.
 */
  reinstated?: boolean;
  /** Task #130 — true when the response is from POST
/feedback/calibration/handwavy-phrases/undo. Omitted on plain
POST/DELETE/reinstate responses.
 */
  undone?: boolean;
  /** Task #132 — true when the response is from POST
/feedback/calibration/handwavy-phrases/revert-edit. Inspect
`edited` to tell whether the revert actually changed anything.
Omitted on other endpoints.
 */
  reverted?: boolean;
  revertedEntry?: HandwavyEditEntry;
  /** The normalized phrase that was added/removed. */
  phrase: string;
  category?: HandwavyCategory;
  /** Number of active phrases after the mutation. */
  total: number;
  marker?: HandwavyMarker;
  historyEntry?: HandwavyHistoryEntry;
  /** Full active list after the mutation. */
  phrases: HandwavyMarker[];
  /** Task #114 — true when the response is a preview only and the phrase was NOT
persisted. When dryRun is true, `dryRunMatches` is populated and the existing
active phrase list (unchanged) is returned in `phrases`.
 */
  dryRun?: boolean;
  dryRunMatches?: HandwavyPhraseDryRunMatches;
  /** Full removal audit log after the mutation (only included on DELETE). */
  history?: HandwavyHistoryEntry[];
  /** Task #119 — Same shape as `dryRunMatches`, but scored against the most
recent N production reports (capped by `dryRunMatchesProductionLimit`)
instead of the curated benchmark cohorts. Production rows are bucketed
into the same T1/T2/T3/T4 tiers as the curated corpus by mapping the
persisted vulnrap composite label (STRONG/PROMISING -> T1, REASONABLE/
NEEDS REVIEW -> T2, LIKELY INVALID -> T3, HIGH RISK -> T4). `corpusSize`
on this block is the number of production reports actually scanned
after dropping rows with no usable label / content. `null` when the
production scan failed (see `dryRunMatchesProductionError`).
 */
  dryRunMatchesProduction?: HandwavyPhraseDryRunMatches | null;
  /** Task #119 — Reviewer-facing notice when the production-archive scan
could not run (e.g. DB unavailable). Null on success. The curated
`dryRunMatches` block is still returned regardless.
 */
  dryRunMatchesProductionError?: string | null;
  /** Task #119 — Upper bound on the number of most-recent production reports
the dry-run scan considered. Reported so reviewers know the depth of
the second signal (e.g. "scanned the last 2000 reports").
 */
  dryRunMatchesProductionLimit?: number;
  dryRunOverlaps?: HandwavyPhraseDryRunOverlaps;
}

